/**
 * @summary Get list of students for a program/year
 */
export const getGetStudentListUrl = (params: GetStudentListParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/student/list?${stringifiedParams}`
    : `/api/student/list`;
};

export const getStudentList = async (
  params: GetStudentListParams,
  options?: RequestInit,
): Promise<StudentInfo[]> => {
  return customFetch<StudentInfo[]>(getGetStudentListUrl(params), {
    ...options,
    method: "GET",
  });
};

